from tkinter import StringVar, TOP, Toplevel
import tkinter
from tkinterdnd2 import TkinterDnD, DND_ALL
import customtkinter as ctk
from PIL import Image, ImageTk
from base64 import b64decode
import os
import tempfile

class Tk(ctk.CTk, TkinterDnD.DnDWrapper):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.TkdndVersion = TkinterDnD._require(self)

icon_main = ""
raw_image = ""
second_window_image = ""  # Asumiré que usas la misma imagen en la segunda ventana, puedes cambiarla si es diferente
icon_zooplus = ""


# Guardar iconos y imágenes en archivos temporales
def save_temp_file(base64_data, suffix):
    temp_file = tempfile.NamedTemporaryFile(delete=False, suffix=suffix)
    temp_file.write(b64decode(base64_data))
    temp_file.close()
    return temp_file.name

# Rutas de los archivos temporales
icon_path = save_temp_file(icon_main, ".ico")
second_window_image_path = save_temp_file(second_window_image, ".png")
icon_path2 = save_temp_file(icon_zooplus, ".ico")

ctk.set_appearance_mode("dark")

def get_path(event):
    pathLabel.configure(text=event.data)

def open_new_window():
    new_window = ctk.CTkToplevel(root)  # Usar CTkToplevel para la nueva ventana
    new_window.geometry("350x300")
    new_window.title("New Window")

    # Establecer el ícono para la nueva ventana
    #new_window.iconbitmap(icon_path2)

    # Cargar la imagen en la nueva ventana
    image = Image.open(second_window_image_path)
    photo = ImageTk.PhotoImage(image)

    new_window.photo = photo
    label2 = ctk.CTkLabel(new_window, image=photo)
    label2.place(x=75, y=75)  # Ajusta la posición según sea necesario

    new_window.lift()  # Trae la nueva ventana al frente
    new_window.grab_set()  # Bloquea la interacción con la ventana principal hasta que se cierre la nueva ventana
    new_window.iconbitmap(icon_path2)

root = Tk()
root.geometry("350x300")
root.title("Get file path")

# Establecer el ícono para la ventana principal
root.iconbitmap(icon_path)

# Cargar la imagen en la ventana principal
image = Image.open(second_window_image_path)
photo = ImageTk.PhotoImage(image)

root.photo = photo
label2 = ctk.CTkLabel(root, image=photo)
label2.place(x=75, y=75)  # Ajusta la posición según sea necesario

nameVar = StringVar()
entryWidget = ctk.CTkEntry(root)
entryWidget.pack(side=TOP, padx=5, pady=5)

pathLabel = ctk.CTkLabel(root, text="Drag and drop file in the entry box")
pathLabel.pack(side=TOP)

entryWidget.drop_target_register(DND_ALL)
entryWidget.dnd_bind("<<Drop>>", get_path)

# Botón para abrir una nueva ventana
button = ctk.CTkButton(root, text="Open New Window", command=open_new_window)
button.pack(side=TOP, pady=10)

root.mainloop()